#include <iostream>
#include <sstream>
#include <vector>
#include <string>

using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode() : val(0), next(nullptr) {}
    ListNode(int x) : val(x), next(nullptr) {}
    ListNode(int x, ListNode *next) : val(x), next(next) {}
};

ListNode* stringToListNode(const string& input) {
    stringstream ss(input);
    int number;
    ListNode* dummy = new ListNode(0);
    ListNode* curr = dummy;
    while (ss >> number) {
        curr->next = new ListNode(number);
        curr = curr->next;
    }
    return dummy->next;
}

void printList(ListNode* node) {
    while (node != nullptr) {
        cout << node->val << (node->next ? " " : "");
        node = node->next;
    }
    cout << endl;
}

// {{USER_CODE}}

int main() {
    string line1, line2;
    if (getline(cin, line1) && getline(cin, line2)) {
        ListNode* l1 = stringToListNode(line1);
        ListNode* l2 = stringToListNode(line2);
        Solution solver;
        ListNode* result = solver.addTwoNumbers(l1, l2);
        printList(result);
    }
    return 0;
}

driverCode.java:
import java.io.*;
import java.util.*;

class ListNode {
    int val;
    ListNode next;
    ListNode() {}
    ListNode(int val) { this.val = val; }
    ListNode(int val, ListNode next) { this.val = val; this.next = next; }
}

// {{USER_CODE}}

public class Main {
    public static ListNode stringToListNode(String input) {
        if (input == null || input.trim().isEmpty()) {
            return null;
        }
        String[] parts = input.trim().split("\\s+");
        ListNode dummy = new ListNode(0);
        ListNode curr = dummy;
        for (String part : parts) {
            curr.next = new ListNode(Integer.parseInt(part));
            curr = curr.next;
        }
        return dummy.next;
    }

    public static void printList(ListNode node) {
        while (node != null) {
            System.out.print(node.val + (node.next != null ? " " : ""));
            node = node.next;
        }
        System.out.println();
    }

    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        String line1 = reader.readLine();
        String line2 = reader.readLine();
        if (line1 != null && line2 != null) {
            ListNode l1 = stringToListNode(line1);
            ListNode l2 = stringToListNode(line2);
            Solution solver = new Solution();
            ListNode result = solver.addTwoNumbers(l1, l2);
            printList(result);
        }
    }
}

