        if (line == null || line.trim().isEmpty()) {
            return;
        }
        StringTokenizer st = new StringTokenizer(line);
        List<Integer> list = new ArrayList<>();
        while (st.hasMoreTokens()) {
            list.add(Integer.parseInt(st.nextToken()));
        }
        int[] nums = new int[list.size()];
