                int minLen = Math.min(a.size(), b.size());
                for (int i = 0; i < minLen; i++) {
                    int cmp = Integer.compare(a.get(i), b.get(i));
                    if (cmp != 0) return cmp;
                }
                return Integer.compare(a.size(), b.size());
            }
        });

