import java.util.*;

class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode() {}
    TreeNode(int val) { this.val = val; }
    TreeNode(int val, TreeNode left, TreeNode right) {
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

// {{USER_CODE}}

public class Main {
    public static String serialize(TreeNode root) {
        if (root == null) return "[]";
        List<String> res = new ArrayList<>();
        Queue<TreeNode> q = new LinkedList<>();
        q.offer(root);
        while (!q.isEmpty()) {
            TreeNode curr = q.poll();
            if (curr != null) {
                res.add(String.valueOf(curr.val));
                q.offer(curr.left);
                q.offer(curr.right);
            }
            else {
                res.add("null");
            }
        }
        while (!res.isEmpty() && res.get(res.size() - 1).equals("null")) {
            res.remove(res.size() - 1);
        }
        StringBuilder sb = new StringBuilder();
        sb.append("[");
        for (int i = 0; i < res.size(); i++) {
            sb.append(res.get(i));
            if (i < res.size() - 1) {
                sb.append(",");
            }
        }
        sb.append("]");
        return sb.toString();
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (sc.hasNextInt()) {
            int n = sc.nextInt();
            Solution solver = new Solution();
            List<TreeNode> trees = solver.generateTrees(n);
            List<String> serialized = new ArrayList<>();
            for (TreeNode root : trees) {
                serialized.add(serialize(root));
            }
            Collections.sort(serialized);
            StringBuilder sb = new StringBuilder();
            sb.append("[");
            for (int i = 0; i < serialized.size(); i++) {
                sb.append(serialized.get(i));
                if (i < serialized.size() - 1) {
                    sb.append(",");
                }
            }
            sb.append("]");
            System.out.println(sb.toString());
        }
    }
}

