                while (i < n - 1 && s.charAt(i) != ']') {
                    if (s.charAt(i) != '"') {
                        arg.append(s.charAt(i));
                    }
                    i++;
                }
                res.add(arg.toString());
            }
            i++;
        }
        return res;
    }

    private static String formatOutput(List<String> list) {
        StringBuilder sb = new StringBuilder();
        sb.append("[");
        for (int i = 0; i < list.size(); i++) {
            sb.append(list.get(i));
            if (i < list.size() - 1) {
                sb.append(",");
            }
        }
        sb.append("]");
        return sb.toString();
    }
}

