        Queue<TreeNode> q = new LinkedList<>();
        q.add(root);
        int i = 1;
        while (!q.isEmpty() && i < tokens.size()) {
            TreeNode curr = q.poll();
            if (i < tokens.size()) {
                if (!tokens.get(i).equals("null")) {
