#include <iostream>
#include <vector>
#include <string>
#include <sstream>
#include <map>
using namespace std;

class SummaryRanges {
    map<int, int> intervals;
public:
    SummaryRanges() {}
    void addNum(int val) {
        auto it = intervals.upper_bound(val);
        int start = val, end = val;
        if (it != intervals.begin()) {
            auto prev = std::prev(it);
            if (prev->second >= val) return;
            if (prev->second == val - 1) {
                start = prev->first;
                intervals.erase(prev);
            }
        }
        if (it != intervals.end() && it->first == val + 1) {
            end = it->second;
            intervals.erase(it);
        }
        intervals[start] = end;
    }
    vector<vector<int>> getIntervals() {
        vector<vector<int>> res;
        for (auto const& [s, e] : intervals) res.push_back({s, e});
        return res;
    }
};

