import java.util.*;

class SummaryRanges {
    private TreeMap<Integer, Integer> intervals;
    public SummaryRanges() {
        intervals = new TreeMap<>();
    }
    public void addNum(int val) {
        Integer lower = intervals.floorKey(val);
        if (lower != null && intervals.get(lower) >= val) return;
        Integer higher = intervals.higherKey(val);
        boolean mergeRight = (higher != null && higher == val + 1);
        boolean mergeLeft = (lower != null && intervals.get(lower) == val - 1);
        if (mergeLeft && mergeRight) {
            intervals.put(lower, intervals.get(higher));
            intervals.remove(higher);
        } else if (mergeLeft) {
            intervals.put(lower, val);
        } else if (mergeRight) {
            intervals.put(val, intervals.get(higher));
            intervals.remove(higher);
        } else {
            intervals.put(val, val);
        }
    }
    public int[][] getIntervals() {
        int[][] res = new int[intervals.size()][2];
        int i = 0;
        for (Map.Entry<Integer, Integer> entry : intervals.entrySet()) {
            res[i][0] = entry.getKey();
            res[i][1] = entry.getValue();
            i++;
        }
        return res;
    }
}

