using namespace std;

class Solution {
    bool solve(vector<double>& nums) {
        if (nums.size() == 1) return abs(nums[0] - 24) < 1e-6;
        for (int i = 0; i < nums.size(); ++i) {
            for (int j = 0; j < nums.size(); ++j) {
                if (i == j) continue;
                vector<double> next;
                for (int k = 0; k < nums.size(); ++k) if (k != i && k != j) next.push_back(nums[k]);
                for (int k = 0; k < 4; ++k) {
                    if (k < 2 && j > i) continue;
                    if (k == 0) next.push_back(nums[i] + nums[j]);
                    else if (k == 1) next.push_back(nums[i] * nums[j]);
                    else if (k == 2) next.push_back(nums[i] - nums[j]);
                    else if (nums[j] != 0) next.push_back(nums[i] / nums[j]);
                    else continue;
                    if (solve(next)) return true;
                    next.pop_back();
                }
            }
        }
        return false;
    }
public:
    bool judgePoint24(vector<int>& cards) {
        vector<double> d(cards.begin(), cards.end());
        return solve(d);
    }
};

