#include <iostream>
#include <vector>
#include <string>
#include <sstream>
#include <queue>
#include <algorithm>

using namespace std;

class Solution {
public:
    int snakesAndLadders(vector<vector<int>>& board) {
        int n = board.size();
        auto getPos = [&](int s) {
            int row = (s - 1) / n;
            int col = (s - 1) % n;
            if (row % 2 == 1) col = n - 1 - col;
            return make_pair(n - 1 - row, col);
        };
        queue<pair<int, int>> q;
        q.push({1, 0});
        vector<int> visited(n * n + 1, 0);
        visited[1] = 1;
        while (!q.empty()) {
            auto [curr, dist] = q.front(); q.pop();
            for (int next = curr + 1; next <= min(curr + 6, n * n); ++next) {
                auto [r, c] = getPos(next);
                int val = (board[r][c] == -1) ? next : board[r][c];
                if (val == n * n) return dist + 1;
                if (!visited[val]) {
                    visited[val] = 1;
                    q.push({val, dist + 1});
                }
            }
        }
        return -1;
    }
};

