class Solution {
    public int snakesAndLadders(int[][] board) {
        int n = board.length;
        Queue<int[]> q = new LinkedList<>();
        q.add(new int[]{1, 0});
        boolean[] visited = new boolean[n * n + 1];
        visited[1] = true;
        while (!q.isEmpty()) {
            int[] curr = q.poll();
            for (int next = curr[0] + 1; next <= Math.min(curr[0] + 6, n * n); next++) {
                int r = n - 1 - (next - 1) / n;
                int c = ((next - 1) / n) % 2 == 0 ? (next - 1) % n : n - 1 - (next - 1) % n;
                int val = board[r][c] == -1 ? next : board[r][c];
                if (val == n * n) return curr[1] + 1;
                if (!visited[val]) {
                    visited[val] = true;
                    q.add(new int[]{val, curr[1] + 1});
                }
            }
        }
        return -1;
    }
